(function() {
  const tv = window.ttyview;
  if (!tv || tv.apiVersion !== 1) return;
  const STORAGE = tv.storage('ttyview-unread');
  // { paneId: { lastViewedTs, unreadCount } }
  const state = STORAGE.get('counts') || {};
  function bump(paneId) {
    state[paneId] = state[paneId] || { lastViewedTs: 0, unreadCount: 0 };
    state[paneId].unreadCount++;
    STORAGE.set('counts', state);
    repaintDot(paneId);
  }
  function clear(paneId) {
    state[paneId] = { lastViewedTs: Date.now(), unreadCount: 0 };
    STORAGE.set('counts', state);
    repaintDot(paneId);
  }
  tv.on('cell-diff',    (d) => { if (d.p !== tv.getActivePane()?.id) bump(d.p); });
  tv.on('pane-changed', (d) => clear(d.to));
  // … repaintDot mutates .ttvtab[data-pane-id] to add a •
})();
```

The repaint runs only on the pinned-tabs row. Plugin's a single file, lives in `community-plugins/ttyview-unread.js`. Want me to wire it?
